    public static void main(String[] args) {
        double x = 710.0;
        double ln2 = 0.6931471805599453;

        double method1 = Math.exp(x - ln2);

        double t = Math.exp(0.5 * x);
        double method2 = (0.5 * t) * t;

        double ref = 1.1169973830808557E308; // From previous run (or Math.cosh if valid)
        // Wait, Math.cosh gave 1.1169973830808557E308 in the first run.

        System.out.println("Ref:      " + ref);
        System.out.println("Method 1: " + method1);
        System.out.println("Method 2: " + method2);

        System.out.println("Diff 1: " + (method1 - ref));
        System.out.println("Diff 2: " + (method2 - ref));

        System.out.println("ULP Ref: " + Math.ulp(ref));
        System.out.println("Error 1 (ULP): " + (method1 - ref) / Math.ulp(ref));
        System.out.println("Error 2 (ULP): " + (method2 - ref) / Math.ulp(ref));
    }
}

